INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the title of the piece. For stories and essays, add a brief thematic hint after a dash. For poetry, the title alone is fine."},"content":{"tips":"Write the complete piece. Use markdown for scene breaks (---), emphasis, and structure. Let the writing breathe."},"formatting":["Paragraphs: the primary unit of prose","Horizontal rules (---): scene breaks in fiction","Blockquotes: pull quotes or epigraphs","Italic: internal thought, emphasis, titles of other works","Headings: section titles in essays (use sparingly in fiction)","Line breaks: critical for poetry (two trailing spaces or blank line)"],"avoid":["Bullet lists in fiction (prose should flow naturally)","Bold text for emphasis (use italics or sentence structure)","Tables or code blocks in creative writing","Explaining the piece — let the writing speak for itself"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":5,"max":150},"content":{"min":100,"max":50000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

